sql:
SELECT villa_name, location, amenities
FROM villas
WHERE bedrooms >= 5;

SELECT amenities
FROM villas
WHERE villa_id = 1;

SELECT guest_id, guest_name, email, phone_number, address, date_of_birth, loyalty_program_member, total_spend 
FROM guests 
WHERE guest_id > 5;

SELECT villa_id
FROM packages
WHERE package_id = (
  SELECT MAX(package_id)
  FROM packages
);

external_knowledge:
- 'Opted for' refers to the guests choosing a package for their booking;
- The non-null package ID confirms they selected a specific package;
- The total booking cost includes all expenses associated with the selected package and villa.

sql:
SELECT villas.villa_name, bookings.start_date, bookings.end_date
FROM villas
JOIN bookings ON villas.villa_id = bookings.villa_id;

SELECT guest_id, guest_name, email, total_spend
FROM guests
WHERE total_spend > 5000.0;

SELECT g.guest_name, b.booking_id
FROM guests g
INNER JOIN bookings b ON g.guest_id = b.guest_id;

external_knowledge:
- "castles" metaphorically represent the "villas";
- "domains" refer to the "locations" of the villas;
- "rivers" metaphorically imply the "payments" or "amounts" of transactions;
- "wealth" is represented by the "average cost", which is the average of the payments made at each villa, providing insight into the financial flow through each "castle's" territory.

sql:
SELECT facility_name, capacity
FROM villa_facilities
WHERE is_premium = 1;

SELECT villa_name 
FROM villas 
WHERE villa_id NOT IN (SELECT villa_id FROM bookings);
